1	// Package storage provides a client interface for object storage backends.
2	package storage
3	
4	import (
5		"context"
6		"encoding/json"
7		"fmt"
8		"io"
9		"mime/multipart"
10		"net/http"
11		"net/textproto"
12		"strings"
13	)
14	
15	// Client abstracts file storage operations so backends can be swapped
16	// or mocked in tests.
17	type Client interface {
18		// Upload stores a file and returns the storage file ID.
19		Upload(ctx context.Context, filename string, reader io.Reader) (fid string, err error)
20		// Download retrieves a file by its storage ID.
21		Download(ctx context.Context, fid string) (io.ReadCloser, error)
22		// Delete removes a file by its storage ID.
23		Delete(ctx context.Context, fid string) error
24	}
25	
26	// assignResponse is the JSON response from SeaweedFS POST /dir/assign.
27	type assignResponse struct {
28		FID       string `json:"fid"`
29		URL       string `json:"url"`
30		PublicURL string `json:"publicUrl"`
31		Count     int    `json:"count"`
32		Error     string `json:"error"`
33	}
34	
35	// SeaweedFSClient interacts with a SeaweedFS cluster over HTTP.
36	type SeaweedFSClient struct {
37		masterURL  string
38		httpClient *http.Client
39	}
40	
41	// NewSeaweedFSClient creates a new SeaweedFS client pointing at the given master URL.
42	func NewSeaweedFSClient(masterURL string, httpClient *http.Client) *SeaweedFSClient {
43		if httpClient == nil {
44			httpClient = http.DefaultClient
45		}
46		// Trim trailing slashes for consistent URL construction.
47		masterURL = strings.TrimRight(masterURL, "/")
48		return &SeaweedFSClient{
49			masterURL:  masterURL,
50			httpClient: httpClient,
51		}
52	}
53	
54	// Upload assigns a file ID from the master, then uploads the file to the
55	// volume server. Returns the assigned fid on success.
56	func (c *SeaweedFSClient) Upload(ctx context.Context, filename string, reader io.Reader) (string, error) {
57		// Step 1: Request a file ID from the master.
58		assignReq, err := http.NewRequestWithContext(ctx, http.MethodPost, c.masterURL+"/dir/assign", nil)
59		if err != nil {
60			return "", fmt.Errorf("seaweedfs assign request: %w", err)
61		}
62	
63		assignResp, err := c.httpClient.Do(assignReq)
64		if err != nil {
65			return "", fmt.Errorf("seaweedfs assign: %w", err)
66		}
67		defer func() { _ = assignResp.Body.Close() }()
68	
69		if assignResp.StatusCode != http.StatusOK {
70			body, _ := io.ReadAll(assignResp.Body)
71			return "", fmt.Errorf("seaweedfs assign: unexpected status %d: %s", assignResp.StatusCode, string(body))
72		}
73	
74		var assign assignResponse
75		if err := json.NewDecoder(assignResp.Body).Decode(&assign); err != nil {
76			return "", fmt.Errorf("seaweedfs assign decode: %w", err)
77		}
78		if assign.Error != "" {
79			return "", fmt.Errorf("seaweedfs assign error: %s", assign.Error)
80		}
81		if assign.FID == "" || assign.URL == "" {
82			return "", fmt.Errorf("seaweedfs assign: empty fid or url")
83		}
84	
85		// Step 2: Upload the file content to the volume server.
86		volumeURL := fmt.Sprintf("http://%s/%s", assign.URL, assign.FID)
87	
88		pr, pw := io.Pipe()
89		writer := multipart.NewWriter(pw)
90	
91		// Write multipart form in a goroutine.
92		errCh := make(chan error, 1)
93		go func() {
94			defer func() { _ = pw.Close() }()
95			h := make(textproto.MIMEHeader)
96			h.Set("Content-Disposition", fmt.Sprintf(`form-data; name="file"; filename="%s"`, filename))
97			h.Set("Content-Type", "application/octet-stream")
98			part, err := writer.CreatePart(h)
99			if err != nil {
100				errCh <- fmt.Errorf("create multipart part: %w", err)
101				return
102			}
103			if _, err := io.Copy(part, reader); err != nil {
104				errCh <- fmt.Errorf("copy to multipart: %w", err)
105				return
106			}
107			errCh <- writer.Close()
108		}()
109	
110		uploadReq, err := http.NewRequestWithContext(ctx, http.MethodPut, volumeURL, pr)
111		if err != nil {
112			return "", fmt.Errorf("seaweedfs upload request: %w", err)
113		}
114		uploadReq.Header.Set("Content-Type", writer.FormDataContentType())
115	
116		uploadResp, err := c.httpClient.Do(uploadReq)
117		if err != nil {
118			return "", fmt.Errorf("seaweedfs upload: %w", err)
119		}
120		defer func() { _ = uploadResp.Body.Close() }()
121	
122		// Wait for the multipart writer goroutine to complete.
123		if writeErr := <-errCh; writeErr != nil {
124			return "", fmt.Errorf("seaweedfs upload multipart write: %w", writeErr)
125		}
126	
127		if uploadResp.StatusCode != http.StatusOK && uploadResp.StatusCode != http.StatusCreated {
128			body, _ := io.ReadAll(uploadResp.Body)
129			return "", fmt.Errorf("seaweedfs upload: unexpected status %d: %s", uploadResp.StatusCode, string(body))
130		}
131	
132		return assign.FID, nil
133	}
134	
135	// Download retrieves the file content for the given fid.
136	// The caller is responsible for closing the returned ReadCloser.
137	func (c *SeaweedFSClient) Download(ctx context.Context, fid string) (io.ReadCloser, error) {
138		// Lookup the volume URL for the fid.
139		lookupURL := fmt.Sprintf("%s/dir/lookup?volumeId=%s", c.masterURL, volumeIDFromFID(fid))
140	
141		lookupReq, err := http.NewRequestWithContext(ctx, http.MethodGet, lookupURL, nil)
142		if err != nil {
143			return nil, fmt.Errorf("seaweedfs lookup request: %w", err)
144		}
145	
146		lookupResp, err := c.httpClient.Do(lookupReq)
147		if err != nil {
148			return nil, fmt.Errorf("seaweedfs lookup: %w", err)
149		}
150		defer func() { _ = lookupResp.Body.Close() }()
151	
152		if lookupResp.StatusCode != http.StatusOK {
153			body, _ := io.ReadAll(lookupResp.Body)
154			return nil, fmt.Errorf("seaweedfs lookup: unexpected status %d: %s", lookupResp.StatusCode, string(body))
155		}
156	
157		var lookup lookupResponse
158		if err := json.NewDecoder(lookupResp.Body).Decode(&lookup); err != nil {
159			return nil, fmt.Errorf("seaweedfs lookup decode: %w", err)
160		}
161		if lookup.Error != "" {
162			return nil, fmt.Errorf("seaweedfs lookup error: %s", lookup.Error)
163		}
164		if len(lookup.Locations) == 0 {
165			return nil, fmt.Errorf("seaweedfs lookup: no locations for fid %s", fid)
166		}
167	
168		downloadURL := fmt.Sprintf("http://%s/%s", lookup.Locations[0].URL, fid)
169		dlReq, err := http.NewRequestWithContext(ctx, http.MethodGet, downloadURL, nil)
170		if err != nil {
171			return nil, fmt.Errorf("seaweedfs download request: %w", err)
172		}
173	
174		dlResp, err := c.httpClient.Do(dlReq)
175		if err != nil {
176			return nil, fmt.Errorf("seaweedfs download: %w", err)
177		}
178	
179		if dlResp.StatusCode != http.StatusOK {
180			body, _ := io.ReadAll(dlResp.Body)
181			_ = dlResp.Body.Close()
182			return nil, fmt.Errorf("seaweedfs download: unexpected status %d: %s", dlResp.StatusCode, string(body))
183		}
184	
185		return dlResp.Body, nil
186	}
187	
188	// Delete removes the file identified by fid from SeaweedFS.
189	func (c *SeaweedFSClient) Delete(ctx context.Context, fid string) error {
190		// Lookup the volume URL for the fid.
191		lookupURL := fmt.Sprintf("%s/dir/lookup?volumeId=%s", c.masterURL, volumeIDFromFID(fid))
192	
193		lookupReq, err := http.NewRequestWithContext(ctx, http.MethodGet, lookupURL, nil)
194		if err != nil {
195			return fmt.Errorf("seaweedfs lookup request: %w", err)
196		}
197	
198		lookupResp, err := c.httpClient.Do(lookupReq)
199		if err != nil {
200			return fmt.Errorf("seaweedfs lookup: %w", err)
201		}
202		defer func() { _ = lookupResp.Body.Close() }()
203	
204		if lookupResp.StatusCode != http.StatusOK {
205			body, _ := io.ReadAll(lookupResp.Body)
206			return fmt.Errorf("seaweedfs lookup: unexpected status %d: %s", lookupResp.StatusCode, string(body))
207		}
208	
209		var lookup lookupResponse
210		if err := json.NewDecoder(lookupResp.Body).Decode(&lookup); err != nil {
211			return fmt.Errorf("seaweedfs lookup decode: %w", err)
212		}
213		if lookup.Error != "" {
214			return fmt.Errorf("seaweedfs lookup error: %s", lookup.Error)
215		}
216		if len(lookup.Locations) == 0 {
217			return fmt.Errorf("seaweedfs lookup: no locations for fid %s", fid)
218		}
219	
220		deleteURL := fmt.Sprintf("http://%s/%s", lookup.Locations[0].URL, fid)
221		delReq, err := http.NewRequestWithContext(ctx, http.MethodDelete, deleteURL, nil)
222		if err != nil {
223			return fmt.Errorf("seaweedfs delete request: %w", err)
224		}
225	
226		delResp, err := c.httpClient.Do(delReq)
227		if err != nil {
228			return fmt.Errorf("seaweedfs delete: %w", err)
229		}
230		defer func() { _ = delResp.Body.Close() }()
231	
232		if delResp.StatusCode != http.StatusOK && delResp.StatusCode != http.StatusAccepted {
233			body, _ := io.ReadAll(delResp.Body)
234			return fmt.Errorf("seaweedfs delete: unexpected status %d: %s", delResp.StatusCode, string(body))
235		}
236	
237		return nil
238	}
239	
240	// lookupResponse is the JSON response from SeaweedFS GET /dir/lookup.
241	type lookupResponse struct {
242		Locations []locationEntry `json:"locations"`
243		Error     string          `json:"error"`
244	}
245	
246	type locationEntry struct {
247		URL       string `json:"url"`
248		PublicURL string `json:"publicUrl"`
249	}
250	
251	// volumeIDFromFID extracts the volume ID portion of a SeaweedFS file ID.
252	// A fid has the format "<volumeId>,<fileKey>" e.g. "3,01637037d6".
253	func volumeIDFromFID(fid string) string {
254		if idx := strings.Index(fid, ","); idx >= 0 {
255			return fid[:idx]
256		}
257		return fid
258	}
259

