// Client abstracts file storage operations so backends can be swapped
// or mocked in tests.
type Client interface {
	// Upload stores a file and returns the storage file ID.
	Upload(ctx context.Context, filename string, reader io.Reader) (fid string, err error)
	// Download retrieves a file by its storage ID.
	Download(ctx context.Context, fid string) (io.ReadCloser, error)
	// Delete removes a file by its storage ID.
	Delete(ctx context.Context, fid string) error
}

// assignResponse is the JSON response from SeaweedFS POST /dir/assign.
type assignResponse struct {
	FID       string `json:"fid"`
	URL       string `json:"url"`
	PublicURL string `json:"publicUrl"`
	Count     int    `json:"count"`
	Error     string `json:"error"`
}

// SeaweedFSClient interacts with a SeaweedFS cluster over HTTP.
type SeaweedFSClient struct {
	masterURL  string
	httpClient *http.Client
}

// NewSeaweedFSClient creates a new SeaweedFS client pointing at the given master URL.
func NewSeaweedFSClient(masterURL string, httpClient *http.Client) *SeaweedFSClient {
	if httpClient == nil {
		httpClient = http.DefaultClient
	}
	// Trim trailing slashes for consistent URL construction.
	masterURL = strings.TrimRight(masterURL, "/")
	return &SeaweedFSClient{
		masterURL:  masterURL,
		httpClient: httpClient,
	}
}

// Upload assigns a file ID from the master, then uploads the file to the
// volume server. Returns the assigned fid on success.
func (c *SeaweedFSClient) Upload(ctx context.Context, filename string, reader io.Reader) (string, error) {
	// Step 1: Request a file ID from the master.
	assignReq, err := http.NewRequestWithContext(ctx, http.MethodPost, c.masterURL+"/dir/assign", nil)
	if err != nil {
		return "", fmt.Errorf("seaweedfs assign request: %w", err)
	}

	assignResp, err := c.httpClient.Do(assignReq)
	if err != nil {
		return "", fmt.Errorf("seaweedfs assign: %w", err)
	}
	defer func() { _ = assignResp.Body.Close() }()

	if assignResp.StatusCode != http.StatusOK {
		body, _ := io.ReadAll(assignResp.Body)
		return "", fmt.Errorf("seaweedfs assign: unexpected status %d: %s", assignResp.StatusCode, string(body))
	}

	var assign assignResponse
	if err := json.NewDecoder(assignResp.Body).Decode(&assign); err != nil {
		return "", fmt.Errorf("seaweedfs assign decode: %w", err)
	}
	if assign.Error != "" {
		return "", fmt.Errorf("seaweedfs assign error: %s", assign.Error)
	}
	if assign.FID == "" || assign.URL == "" {
		return "", fmt.Errorf("seaweedfs assign: empty fid or url")
	}

	// Step 2: Upload the file content to the volume server.
	volumeURL := fmt.Sprintf("http://%s/%s", assign.URL, assign.FID)

	pr, pw := io.Pipe()
	writer := multipart.NewWriter(pw)

	// Write multipart form in a goroutine.
	errCh := make(chan error, 1)
	go func() {
		defer func() { _ = pw.Close() }()
		h := make(textproto.MIMEHeader)
		h.Set("Content-Disposition", fmt.Sprintf(`form-data; name="file"; filename="%s"`, filename))
		h.Set("Content-Type", "application/octet-stream")
		part, err := writer.CreatePart(h)
		if err != nil {
			errCh <- fmt.Errorf("create multipart part: %w", err)
			return
		}
		if _, err := io.Copy(part, reader); err != nil {
			errCh <- fmt.Errorf("copy to multipart: %w", err)
			return
		}
		errCh <- writer.Close()
	}()

	uploadReq, err := http.NewRequestWithContext(ctx, http.MethodPut, volumeURL, pr)
	if err != nil {
		return "", fmt.Errorf("seaweedfs upload request: %w", err)
	}
	uploadReq.Header.Set("Content-Type", writer.FormDataContentType())

	uploadResp, err := c.httpClient.Do(uploadReq)
	if err != nil {
		return "", fmt.Errorf("seaweedfs upload: %w", err)
	}
	defer func() { _ = uploadResp.Body.Close() }()

	// Wait for the multipart writer goroutine to complete.
	if writeErr := <-errCh; writeErr != nil {
		return "", fmt.Errorf("seaweedfs upload multipart write: %w", writeErr)
	}

	if uploadResp.StatusCode != http.StatusOK && uploadResp.StatusCode != http.StatusCreated {
		body, _ := io.ReadAll(uploadResp.Body)
		return "", fmt.Errorf("seaweedfs upload: unexpected status %d: %s", uploadResp.StatusCode, string(body))
	}

	return assign.FID, nil
}

// Download retrieves the file content for the given fid.
// The caller is responsible for closing the returned ReadCloser.
func (c *SeaweedFSClient) Download(ctx context.Context, fid string) (io.ReadCloser, error) {
	// Lookup the volume URL for the fid.
	lookupURL := fmt.Sprintf("%s/dir/lookup?volumeId=%s", c.masterURL, volumeIDFromFID(fid))

	lookupReq, err := http.NewRequestWithContext(ctx, http.MethodGet, lookupURL, nil)
	if err != nil {
		return nil, fmt.Errorf("seaweedfs lookup request: %w", err)
	}

	lookupResp, err := c.httpClient.Do(lookupReq)
	if err != nil {
		return nil, fmt.Errorf("seaweedfs lookup: %w", err)
	}
	defer func() { _ = lookupResp.Body.Close() }()

	if lookupResp.StatusCode != http.StatusOK {
		body, _ := io.ReadAll(lookupResp.Body)
		return nil, fmt.Errorf("seaweedfs lookup: unexpected status %d: %s", lookupResp.StatusCode, string(body))
	}

	var lookup lookupResponse
	if err := json.NewDecoder(lookupResp.Body).Decode(&lookup); err != nil {
		return nil, fmt.Errorf("seaweedfs lookup decode: %w", err)
	}
	if lookup.Error != "" {
		return nil, fmt.Errorf("seaweedfs lookup error: %s", lookup.Error)
	}
	if len(lookup.Locations) == 0 {
		return nil, fmt.Errorf("seaweedfs lookup: no locations for fid %s", fid)
	}

	downloadURL := fmt.Sprintf("http://%s/%s", lookup.Locations[0].URL, fid)
	dlReq, err := http.NewRequestWithContext(ctx, http.MethodGet, downloadURL, nil)
	if err != nil {
		return nil, fmt.Errorf("seaweedfs download request: %w", err)
	}

	dlResp, err := c.httpClient.Do(dlReq)
	if err != nil {
		return nil, fmt.Errorf("seaweedfs download: %w", err)
	}

	if dlResp.StatusCode != http.StatusOK {
		body, _ := io.ReadAll(dlResp.Body)
		_ = dlResp.Body.Close()
		return nil, fmt.Errorf("seaweedfs download: unexpected status %d: %s", dlResp.StatusCode, string(body))
	}

	return dlResp.Body, nil
}

// Delete removes the file identified by fid from SeaweedFS.
func (c *SeaweedFSClient) Delete(ctx context.Context, fid string) error {
	// Lookup the volume URL for the fid.
	lookupURL := fmt.Sprintf("%s/dir/lookup?volumeId=%s", c.masterURL, volumeIDFromFID(fid))

	lookupReq, err := http.NewRequestWithContext(ctx, http.MethodGet, lookupURL, nil)
	if err != nil {
		return fmt.Errorf("seaweedfs lookup request: %w", err)
	}

	lookupResp, err := c.httpClient.Do(lookupReq)
	if err != nil {
		return fmt.Errorf("seaweedfs lookup: %w", err)
	}
	defer func() { _ = lookupResp.Body.Close() }()

	if lookupResp.StatusCode != http.StatusOK {
		body, _ := io.ReadAll(lookupResp.Body)
		return fmt.Errorf("seaweedfs lookup: unexpected status %d: %s", lookupResp.StatusCode, string(body))
	}

	var lookup lookupResponse
	if err := json.NewDecoder(lookupResp.Body).Decode(&lookup); err != nil {
		return fmt.Errorf("seaweedfs lookup decode: %w", err)
	}
	if lookup.Error != "" {
		return fmt.Errorf("seaweedfs lookup error: %s", lookup.Error)
	}
	if len(lookup.Locations) == 0 {
		return fmt.Errorf("seaweedfs lookup: no locations for fid %s", fid)
	}

	deleteURL := fmt.Sprintf("http://%s/%s", lookup.Locations[0].URL, fid)
	delReq, err := http.NewRequestWithContext(ctx, http.MethodDelete, deleteURL, nil)
	if err != nil {
		return fmt.Errorf("seaweedfs delete request: %w", err)
	}

	delResp, err := c.httpClient.Do(delReq)
	if err != nil {
		return fmt.Errorf("seaweedfs delete: %w", err)
	}
	defer func() { _ = delResp.Body.Close() }()

	if delResp.StatusCode != http.StatusOK && delResp.StatusCode != http.StatusAccepted {
		body, _ := io.ReadAll(delResp.Body)
		return fmt.Errorf("seaweedfs delete: unexpected status %d: %s", delResp.StatusCode, string(body))
	}

	return nil
}

// lookupResponse is the JSON response from SeaweedFS GET /dir/lookup.
type lookupResponse struct {
	Locations []locationEntry `json:"locations"`
	Error     string          `json:"error"`
}

type locationEntry struct {
	URL       string `json:"url"`
	PublicURL string `json:"publicUrl"`
}

// volumeIDFromFID extracts the volume ID portion of a SeaweedFS file ID.
// A fid has the format "<volumeId>,<fileKey>" e.g. "3,01637037d6".
func volumeIDFromFID(fid string) string {
	if idx := strings.Index(fid, ","); idx >= 0 {
		return fid[:idx]
	}
	return fid
}

package handler

import (
	"context"
	"encoding/json"
	"errors"
	"io"
	"log/slog"
	"net/http"
	"strconv"

	"github.com/gin-gonic/gin"

	"github.com/ravencloak-org/Raven/internal/model"
	"github.com/ravencloak-org/Raven/internal/service"
	"github.com/ravencloak-org/Raven/pkg/apierror"
)

// WhatsAppWebhookServicer is the interface the handler requires from the service layer.
type WhatsAppWebhookServicer interface {
	VerifyWebhook(mode, token, challenge string) (string, error)
	ValidateSignature(payload []byte, signatureHeader string) bool
	HandleCallStarted(ctx context.Context, phoneNumberID, callID, from, to, sdpOffer string) (*model.WhatsAppCall, error)
	HandleCallConnected(ctx context.Context, phoneNumberID, callID string) (*model.WhatsAppCall, error)
	HandleCallEnded(ctx context.Context, phoneNumberID, callID string) (*model.WhatsAppCall, error)
	SetSDPAnswer(ctx context.Context, orgID, callID, sdpAnswer string) (*model.WhatsAppCall, error)
	GetCall(ctx context.Context, orgID, id string) (*model.WhatsAppCall, error)
	ListCalls(ctx context.Context, orgID string, limit, offset int) (*model.WhatsAppCallListResponse, error)
}

// WhatsAppWebhookHandler handles incoming Meta webhook requests for WhatsApp calling.
type WhatsAppWebhookHandler struct {
	svc WhatsAppWebhookServicer
}

// NewWhatsAppWebhookHandler creates a new WhatsAppWebhookHandler.
func NewWhatsAppWebhookHandler(svc WhatsAppWebhookServicer) *WhatsAppWebhookHandler {
	return &WhatsAppWebhookHandler{svc: svc}
}

// Verify handles GET /webhooks/whatsapp — Meta's webhook verification challenge.
//
// @Summary     Verify WhatsApp webhook
// @Description Responds to Meta's webhook verification challenge during setup.
// @Tags        whatsapp-webhooks
// @Produce     plain
// @Param       hub.mode         query string true "Must be 'subscribe'"
// @Param       hub.verify_token query string true "Verification token"
// @Param       hub.challenge    query string true "Challenge string to echo back"
// @Success     200 {string} string "The hub.challenge value"
// @Failure     400 {object} apierror.AppError
// @Failure     401 {object} apierror.AppError
// @Router      /webhooks/whatsapp [get]
func (h *WhatsAppWebhookHandler) Verify(c *gin.Context) {
	mode := c.Query("hub.mode")
	token := c.Query("hub.verify_token")
	challenge := c.Query("hub.challenge")

	result, err := h.svc.VerifyWebhook(mode, token, challenge)
	if err != nil {
		_ = c.Error(translateWebhookError(err))
		c.Abort()
		return
	}

	c.String(http.StatusOK, result)
}

// webhookPayload represents the top-level structure of a Meta webhook notification.
type webhookPayload struct {
	Object string         `json:"object"`
	Entry  []webhookEntry `json:"entry"`
}

// webhookEntry represents a single entry in the Meta webhook payload.
type webhookEntry struct {
	ID      string           `json:"id"`
	Changes []webhookChange  `json:"changes"`
}

// webhookChange represents a change object within a webhook entry.
type webhookChange struct {
	Field string          `json:"field"`
	Value webhookValue    `json:"value"`
}

// webhookValue contains the actual event data.
type webhookValue struct {
	MessagingProduct string                 `json:"messaging_product"`
	Metadata         webhookMetadata        `json:"metadata,omitempty"`
	Calls            []webhookCallEvent     `json:"calls,omitempty"`
}

// webhookMetadata contains metadata about the WhatsApp Business Account.
type webhookMetadata struct {
	DisplayPhoneNumber string `json:"display_phone_number"`
	PhoneNumberID      string `json:"phone_number_id"`
}

// webhookCallEvent represents a single call event in the webhook.
type webhookCallEvent struct {
	ID        string `json:"id"`
	From      string `json:"from"`
	To        string `json:"to"`
	Type      string `json:"type"`
	Status    string `json:"status"`
	SDPOffer  string `json:"sdp_offer,omitempty"`
}

// Receive handles POST /webhooks/whatsapp — incoming Meta webhook events.
//
// @Summary     Receive WhatsApp webhook events
// @Description Processes incoming webhook events from Meta (call events, etc).
// @Tags        whatsapp-webhooks
// @Accept      json
// @Produce     json
// @Success     200 {string} string "ok"
// @Failure     400 {object} apierror.AppError
// @Failure     401 {object} apierror.AppError
// @Router      /webhooks/whatsapp [post]
func (h *WhatsAppWebhookHandler) Receive(c *gin.Context) {
	// Read the raw body for signature verification.
	body, err := io.ReadAll(c.Request.Body)
	if err != nil {
		_ = c.Error(apierror.NewBadRequest("failed to read request body"))
		c.Abort()
		return
	}

	// Validate HMAC-SHA256 signature.
	signature := c.GetHeader("X-Hub-Signature-256")
	if !h.svc.ValidateSignature(body, signature) {
		_ = c.Error(apierror.NewUnauthorized("invalid webhook signature"))
		c.Abort()
		return
	}

	// Parse the webhook payload from the raw bytes (body was already consumed above).
	var payload webhookPayload
	if err := parseJSON(body, &payload); err != nil {
		_ = c.Error(apierror.NewBadRequest("invalid webhook payload"))
		c.Abort()
		return
	}

	// Process each entry.
	for _, entry := range payload.Entry {
		for _, change := range entry.Changes {
			h.processChange(c.Request.Context(), change)
		}
	}

	// Always respond with 200 to acknowledge receipt — Meta retries on non-2xx.
	c.String(http.StatusOK, "ok")
}

// processChange routes a single change to the appropriate call event handler.
func (h *WhatsAppWebhookHandler) processChange(ctx context.Context, change webhookChange) {
	phoneNumberID := change.Value.Metadata.PhoneNumberID

	for _, callEvent := range change.Value.Calls {
		switch callEvent.Status {
		case "ringing", "voice_call_started":
			if _, err := h.svc.HandleCallStarted(ctx, phoneNumberID, callEvent.ID, callEvent.From, callEvent.To, callEvent.SDPOffer); err != nil {
				slog.ErrorContext(ctx, "failed to handle call started",
					"call_id", callEvent.ID,
					"error", err,
				)
			}
		case "connected", "voice_call_connected":
			if _, err := h.svc.HandleCallConnected(ctx, phoneNumberID, callEvent.ID); err != nil {
				slog.ErrorContext(ctx, "failed to handle call connected",
					"call_id", callEvent.ID,
					"error", err,
				)
			}
		case "ended", "voice_call_ended":
			if _, err := h.svc.HandleCallEnded(ctx, phoneNumberID, callEvent.ID); err != nil {
				slog.ErrorContext(ctx, "failed to handle call ended",
					"call_id", callEvent.ID,
					"error", err,
				)
			}
		default:
			slog.WarnContext(ctx, "unknown WhatsApp call event status",
				"status", callEvent.Status,
				"call_id", callEvent.ID,
			)
		}
	}
}

// GetCall handles GET /orgs/:org_id/whatsapp/calls/:call_id.
//
// @Summary     Get WhatsApp call
// @Description Returns a WhatsApp call record by ID.
// @Tags        whatsapp-calls
// @Produce     json
// @Security    BearerAuth
// @Param       org_id  path string true "Organisation ID"
// @Param       call_id path string true "Call ID (internal UUID)"
// @Success     200 {object} model.WhatsAppCallResponse
// @Failure     401 {object} apierror.AppError
// @Failure     404 {object} apierror.AppError
// @Router      /orgs/{org_id}/whatsapp/calls/{call_id} [get]
func (h *WhatsAppWebhookHandler) GetCall(c *gin.Context) {
	orgID, ok := extractOrgID(c)
	if !ok {
		return
	}
	callID := c.Param("call_id")

	call, err := h.svc.GetCall(c.Request.Context(), orgID, callID)
	if err != nil {
		_ = c.Error(translateWebhookError(err))
		c.Abort()
		return
	}
	c.JSON(http.StatusOK, model.WhatsAppCallResponse{Call: *call})
}

// ListCalls handles GET /orgs/:org_id/whatsapp/calls.
//
// @Summary     List WhatsApp calls
// @Description Returns org-scoped WhatsApp calls with pagination.
// @Tags        whatsapp-calls
// @Produce     json
// @Security    BearerAuth
// @Param       org_id path  string true  "Organisation ID"
// @Param       limit  query int    false "Number of calls (default 20)"
// @Param       offset query int    false "Offset (default 0)"
// @Success     200 {object} model.WhatsAppCallListResponse
// @Failure     401 {object} apierror.AppError
// @Failure     500 {object} apierror.AppError
// @Router      /orgs/{org_id}/whatsapp/calls [get]
func (h *WhatsAppWebhookHandler) ListCalls(c *gin.Context) {
	orgID, ok := extractOrgID(c)
	if !ok {
		return
	}

	limit, _ := strconv.Atoi(c.DefaultQuery("limit", "20"))
	offset, _ := strconv.Atoi(c.DefaultQuery("offset", "0"))

	resp, err := h.svc.ListCalls(c.Request.Context(), orgID, limit, offset)
	if err != nil {
		_ = c.Error(translateWebhookError(err))
		c.Abort()
		return
	}
	c.JSON(http.StatusOK, resp)
}

// SendSDPAnswer handles POST /orgs/:org_id/whatsapp/calls/:call_id/answer.
//
// @Summary     Send SDP answer for a WhatsApp call
// @Description Stores the SDP answer and (in a future version) sends it to Meta.
// @Tags        whatsapp-calls
// @Accept      json
// @Produce     json
// @Security    BearerAuth
// @Param       org_id  path string true "Organisation ID"
// @Param       call_id path string true "Meta's external call ID"
// @Param       request body model.SendSDPAnswerRequest true "SDP answer payload"
// @Success     200 {object} model.WhatsAppCallResponse
// @Failure     400 {object} apierror.AppError
// @Failure     401 {object} apierror.AppError
// @Failure     404 {object} apierror.AppError
// @Router      /orgs/{org_id}/whatsapp/calls/{call_id}/answer [post]
func (h *WhatsAppWebhookHandler) SendSDPAnswer(c *gin.Context) {
	orgID, ok := extractOrgID(c)
	if !ok {
		return
	}
	callID := c.Param("call_id")

	var req struct {
		SDPAnswer string `json:"sdp_answer" binding:"required"`
	}
	if err := c.ShouldBindJSON(&req); err != nil {
		_ = c.Error(&apierror.AppError{
			Code:    http.StatusBadRequest,
			Message: "Bad Request",
			Detail:  err.Error(),
		})
		c.Abort()
		return
	}

	call, err := h.svc.SetSDPAnswer(c.Request.Context(), orgID, callID, req.SDPAnswer)
	if err != nil {
		_ = c.Error(translateWebhookError(err))
		c.Abort()
		return
	}
	c.JSON(http.StatusOK, call)
}

// translateWebhookError maps service-layer sentinel errors to HTTP-shaped apierror values.
// Any error that is not a known sentinel is returned as a 500 Internal Server Error.
func translateWebhookError(err error) *apierror.AppError {
	switch {
	case errors.Is(err, service.ErrWebhookInvalidMode):
		return apierror.NewBadRequest(err.Error())
	case errors.Is(err, service.ErrWebhookChallengeMissing):
		return apierror.NewBadRequest(err.Error())
	case errors.Is(err, service.ErrWebhookTokenMismatch):
		return apierror.NewUnauthorized(err.Error())
	case errors.Is(err, service.ErrWebhookCallNotFound):
		return apierror.NewNotFound(err.Error())
	case errors.Is(err, service.ErrWebhookInternal):
		return apierror.NewInternal(err.Error())
	default:
		return apierror.NewInternal(err.Error())
	}
}

// parseJSON is a helper to parse JSON from raw bytes.
func parseJSON(data []byte, v any) error {
	return json.Unmarshal(data, v)
}

package handler

import (
	"net/http"

	"github.com/gin-gonic/gin"
	"github.com/supertokens/supertokens-golang/supertokens"
)

// SuperTokensMiddleware returns a Gin middleware that delegates all SuperTokens
// auth routes (e.g. /auth/signinup, /auth/session/refresh) to the SuperTokens
// Go SDK. The SDK must be initialised via auth.InitSuperTokens before use.
//
// Register with router.Use(handler.SuperTokensMiddleware()) BEFORE other routes
// so the SDK can intercept /auth/* requests before Gin processes them.
func SuperTokensMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		handled := false

		supertokens.Middleware(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// This inner handler is only called when SuperTokens did NOT handle
			// the request (i.e. the path is not an /auth/* SDK endpoint).
			// Signal that control should pass to subsequent Gin handlers.
			handled = false
		})).ServeHTTP(c.Writer, c.Request)

		// If the response was already written by the SDK, abort the Gin chain
		// to prevent double-writing.
		if c.Writer.Written() {
			handled = true
		}

		if handled {
			c.Abort()
			return
		}

		c.Next()
	}
}

package middleware

import (
	"sync"
	"time"

	"github.com/gin-contrib/cors"
	"github.com/gin-gonic/gin"
	"github.com/samber/lo"
	"github.com/supertokens/supertokens-golang/supertokens"

	"github.com/ravencloak-org/Raven/internal/config"
)

// stCORSHeadersOnce caches the result of supertokens.GetAllCORSHeaders() so
// we only call it once per process and do not pay the overhead on every CORS
// middleware construction.
var (
	stCORSOnce    sync.Once
	stCORSHeaders []string
)

// getSuperTokensCORSHeaders returns the headers required by the SuperTokens Go
// SDK. It is computed lazily on first call; if the SDK is not yet initialised
// (e.g. in unit tests that construct the CORS middleware without a running
// Core) it falls back to the well-known static set so tests remain stable.
func getSuperTokensCORSHeaders() []string {
	stCORSOnce.Do(func() {
		defer func() {
			if r := recover(); r != nil {
				// SDK not initialised (e.g. unit test context). Fall back to
				// the well-known static set that SuperTokens always requires.
				stCORSHeaders = []string{
					"anti-csrf",
					"st-auth-mode",
					"rid",
					"fdi-version",
				}
			}
		}()
		stCORSHeaders = supertokens.GetAllCORSHeaders()
	})
	return stCORSHeaders
}

// CORSMiddleware returns a Gin handler that applies CORS policy based on the
// provided CORSConfig. Origins are validated against cfg.AllowedOrigins.
// AllowOriginFunc mirrors the same list so that pre-flight and actual requests
// both use one consistent source of truth; the comment block marks the place
// where per-key allowed_domains will be wired in during a later milestone.
func CORSMiddleware(cfg *config.CORSConfig) gin.HandlerFunc {
	if cfg == nil {
		cfg = &config.CORSConfig{}
	}

	allowedSet := lo.SliceToMap(cfg.AllowedOrigins, func(o string) (string, struct{}) {
		return o, struct{}{}
	})

	// Merge the SDK-required headers with our application-specific headers so
	// that both sets are always in sync with the SuperTokens version in use.
	appHeaders := []string{
		"Authorization",
		"Content-Type",
		"X-API-Key",
		"X-Request-ID",
	}
	allowHeaders := lo.Uniq(append(appHeaders, getSuperTokensCORSHeaders()...))

	corsConfig := cors.Config{
		AllowMethods: []string{
			"GET", "POST", "PUT", "DELETE", "OPTIONS", "PATCH",
		},
		AllowHeaders: allowHeaders,
		ExposeHeaders: []string{
			"st-access-token",
			"st-refresh-token",
			"anti-csrf",
			"front-token",
		},
		AllowCredentials: true,
		MaxAge:           time.Duration(3600) * time.Second,
		// AllowOriginFunc takes precedence over AllowOrigins when set.
		// It checks the request origin against the configured allow-list.
		// TODO(M2): also check api_keys.allowed_domains from the database.
		AllowOriginFunc: func(origin string) bool {
			_, ok := allowedSet[origin]
			return ok
		},
	}

	return cors.New(corsConfig)
}

package auth

import (
	"github.com/supertokens/supertokens-golang/recipe/session"
	"github.com/supertokens/supertokens-golang/recipe/thirdparty"
	"github.com/supertokens/supertokens-golang/recipe/thirdparty/tpmodels"
	"github.com/supertokens/supertokens-golang/supertokens"
)

// SuperTokensInitConfig holds the parameters required to initialise the
// SuperTokens Go SDK. APIDomain and WebsiteDomain come from config so that
// the same binary can run locally (localhost) or in production (ravencloak.org).
type SuperTokensInitConfig struct {
	ConnectionURI      string
	APIKey             string
	APIDomain          string // e.g. https://api.ravencloak.org
	WebsiteDomain      string // e.g. https://app.ravencloak.org
	GoogleClientID     string
	GoogleClientSecret string
}

// InitSuperTokens initialises the SuperTokens Go SDK with the ThirdParty and
// Session recipes. The SDK must be initialised once, before any route
// registration, so that supertokens.Middleware can intercept /auth/* paths.
//
// Google OAuth credentials are optional here: when multitenancy is used the
// provider configuration lives in the Core and does not need to be repeated
// in the SDK init. Pass them only for single-tenant / static setups.
func InitSuperTokens(cfg SuperTokensInitConfig) error {
	apiBasePath := "/auth"
	websiteBasePath := "/auth"

	recipeList := []supertokens.Recipe{
		thirdparty.Init(&tpmodels.TypeInput{
			// Provider list is managed via the SuperTokens Core multitenancy API.
			// Static providers can be added here for single-tenant deployments.
		}),
		session.Init(nil),
	}

	return supertokens.Init(supertokens.TypeInput{
		Supertokens: &supertokens.ConnectionInfo{
			ConnectionURI: cfg.ConnectionURI,
			APIKey:        cfg.APIKey,
		},
		AppInfo: supertokens.AppInfo{
			AppName:         "Raven",
			APIDomain:       cfg.APIDomain,
			WebsiteDomain:   cfg.WebsiteDomain,
			APIBasePath:     &apiBasePath,
			WebsiteBasePath: &websiteBasePath,
		},
		RecipeList: recipeList,
	})
}

