package auth

import (
	"fmt"
	"net/http"

	"github.com/supertokens/supertokens-golang/recipe/session"
)

// SuperTokensProvider implements AuthProvider using the SuperTokens Go SDK.
// The SDK must be initialised via InitSuperTokens before any method is called.
type SuperTokensProvider struct{}

// NewSuperTokensProvider creates a provider backed by the SuperTokens Go SDK.
// The SDK is expected to already be initialised (call InitSuperTokens once at
// startup, before creating this provider).
func NewSuperTokensProvider() *SuperTokensProvider {
	return &SuperTokensProvider{}
}

// VerifySession validates the session embedded in the request (via
// sAccessToken cookie or Authorization header) using the SuperTokens SDK.
// It returns a SessionInfo containing the SuperTokens user ID; email and name
// are populated later by the UserLookup middleware from the local database.
func (p *SuperTokensProvider) VerifySession(r *http.Request) (*SessionInfo, error) {
	// session.GetSession reads the access token from the request cookies /
	// Authorization header, verifies the JWT signature against the Core, and
	// (optionally) does a database check for revocation.
	//
	// We pass nil for res so no Set-Cookie headers are written; the SDK falls
	// back gracefully when res is nil during verification-only calls.
	sessionContainer, err := session.GetSession(r, nil, nil)
	if err != nil {
		return nil, fmt.Errorf("session verification failed: %w", err)
	}
	if sessionContainer == nil {
		return nil, fmt.Errorf("no session found")
	}

	userID := sessionContainer.GetUserID()

	// Extract email and name from the access token payload if present.
	// SuperTokens stores these when configured with session claims.
	var email, name string
	payload := sessionContainer.GetAccessTokenPayload()
	if e, ok := payload["email"].(string); ok {
		email = e
	}
	if n, ok := payload["name"].(string); ok {
		name = n
	}

	return &SessionInfo{
		ExternalID: userID,
		Email:      email,
		Name:       name,
	}, nil
}

// RevokeSession invalidates the session identified by the request's access token.
func (p *SuperTokensProvider) RevokeSession(r *http.Request) error {
	sessionContainer, err := session.GetSession(r, nil, nil)
	if err != nil {
		return fmt.Errorf("session verification failed: %w", err)
	}
	if sessionContainer == nil {
		return fmt.Errorf("no session found")
	}
	return sessionContainer.RevokeSession()
}

	return nil
}

// FindByHash looks up an existing document by its file hash within a knowledge base.
func (r *DocumentRepository) FindByHash(ctx context.Context, tx pgx.Tx, orgID, kbID, fileHash string) (*model.Document, error) {
	row := tx.QueryRow(ctx,
		`SELECT id, org_id, knowledge_base_id, file_name, file_type, file_size_bytes,
		        file_hash, storage_path, processing_status, processing_error,
		        title, page_count, metadata, uploaded_by, created_at, updated_at
		 FROM documents
		 WHERE org_id = $1 AND knowledge_base_id = $2 AND file_hash = $3
		 LIMIT 1`,
		orgID, kbID, fileHash,
	)
	var doc model.Document
	var fileSizeBytes *int64
	var pageCount *int
	var processingError, title *string
	err := row.Scan(
		&doc.ID, &doc.OrgID, &doc.KnowledgeBaseID, &doc.FileName, &doc.FileType,
		&fileSizeBytes, &doc.FileHash, &doc.StoragePath, &doc.ProcessingStatus,
		&processingError, &title, &pageCount, &doc.Metadata, &doc.UploadedBy,
		&doc.CreatedAt, &doc.UpdatedAt,
	)
	if err != nil {
		if err == pgx.ErrNoRows {
			return nil, nil
		}
		return nil, fmt.Errorf("DocumentRepository.FindByHash: %w", err)
	}
	doc.FileSizeBytes = fileSizeBytes
	doc.PageCount = pageCount
	if processingError != nil {
		doc.ProcessingError = *processingError
	}
	if title != nil {
		doc.Title = *title
	}
	return &doc, nil
}

